# Core geometry types and interfaces
from math_utils import PI, square

interface IShape:
    def area(self) -> float: ...
    def perimeter(self) -> float: ...
    def name(self) -> str: ...

struct Point:
    x: float
    y: float

    def distance_to(self, other: Point) -> float:
        dx: float = self.x - other.x
        dy: float = self.y - other.y
        return pow((dx * dx) + (dy * dy), 0.5)

struct Rectangle:
    width: float
    height: float

    def __init__(self, w: float, h: float):
        self.width = w
        self.height = h

class ShapeRectangle(Rectangle, IShape):
    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    def name(self) -> str:
        return "Rectangle"

struct Circle:
    radius: float

    def __init__(self, r: float):
        self.radius = r

class ShapeCircle(Circle, IShape):
    def area(self) -> float:
        return PI * square(self.radius)

    def perimeter(self) -> float:
        return 2.0 * PI * self.radius

    def name(self) -> str:
        return "Circle"

