# Shape registry and factory
from geometry_types import IShape, ShapeRectangle, ShapeCircle, Point
from math_utils import Operation, apply_operation

class ShapeRegistry:
    shapes: list[IShape]
    _next_id: int

    def __init__(self):
        self.shapes = []
        self._next_id = 0

    def add(self, shape: IShape):
        self.shapes.append(shape)
        self._next_id += 1

    def total_area(self) -> float:
        total: float = 0.0
        for s in self.shapes:
            total += s.area()
        return total

    def total_perimeter(self) -> float:
        total: float = 0.0
        for s in self.shapes:
            total += s.perimeter()
        return total

    def describe_all(self):
        for s in self.shapes:
            pass

    def count(self) -> int:
        return len(self.shapes)

def create_rectangle(w: float, h: float) -> ShapeRectangle:
    return ShapeRectangle(w, h)

def create_circle(r: float) -> ShapeCircle:
    return ShapeCircle(r)
